mapper.select:
SELECT p.post_no AS postNo, p.user_id AS userId, p.category, p.title, p.content, p.reg_date AS regDate, p.view_cnt AS viewCnt, p.like_cnt AS likeCnt, p.is_deleted AS isDeleted,
( SELECT COUNT(*) FROM comment c WHERE c.post_no = p.post_no AND c.is_deleted = 0 ) AS commentCnt
FROM Community_Post p WHERE p.post_no = #{postNo}

