mapper.select:
SELECT * FROM payment
ORDER BY pay_no DESC
LIMIT #{pageSize} OFFSET #{offSet}

SELECT p.product_no AS productNo, p.company_no AS companyNo, p.product_name AS productName, p.product_details AS productDetails, p.original_price AS originalPrice, p.is_active AS isActive, p.img_url AS imgUrl, p.pro_type AS proType, p.tag AS tag, p.deposit AS deposit, c.com_name AS comName FROM product p LEFT JOIN company c ON p.company_no = c.company_no
AND ( p.product_name LIKE CONCAT('%', #{keyword}, '%') OR c.com_name LIKE CONCAT('%', #{keyword}, '%') )
AND p.is_active = #{status}
ORDER BY p.product_no DESC LIMIT #{pageSize} OFFSET #{offSet}

SELECT COUNT(*) FROM product p LEFT JOIN company c ON p.company_no = c.company_no
AND ( p.product_name LIKE CONCAT('%', #{keyword}, '%') OR c.com_name LIKE CONCAT('%', #{keyword}, '%') )
AND p.is_active = #{status}

mapper.update:
UPDATE product
SET is_active = #{isActive}
WHERE product_no = #{productNo}

mapper.select:
SELECT coupon_code AS couponCode, coupon_name AS couponName, discount_rate AS discountRate, issue_type AS issueType, max_issue_cnt AS maxIssueCnt FROM coupon WHERE 1=1
AND ( coupon_code LIKE CONCAT('%', #{keyword}, '%') OR coupon_name LIKE CONCAT('%', #{keyword}, '%') )
ORDER BY coupon_code DESC LIMIT #{pageSize} OFFSET #{offSet}

SELECT pass_no AS passNo, pass_name AS passName, price AS price, review_cnt AS reviewCnt, is_active AS isActive, reg_date AS regDate FROM pass_product WHERE 1 = 1
AND pass_name LIKE CONCAT('%', #{keyword}, '%')
AND is_active = #{status}
ORDER BY pass_no DESC LIMIT #{pageSize} OFFSET #{offSet}

SELECT COUNT(*) FROM pass_product WHERE 1 = 1
AND pass_name LIKE CONCAT('%', #{keyword}, '%')
AND is_active = #{status}

